const query = $json.query || {};
const body = $json.body || $json;
const message = query.message || body.message || body.goal || '';
const projectId = query.project_id || body.project_id || ('proj-' + Date.now());
const reference_url = query.reference_url || body.reference_url || null;
const image_data = body.image_data || null;
return [{ json: { message, project_id: projectId, operation: 'init', goal: message, reference_url, image_data } }];

// MODIFIED: Absorbs Research: Build Project Context
// Caches _allFileContents, _researchDocs, _projectFileList in static data
// so Phase 2 chunks don't need to re-fetch or re-compute.
const memory = $('Extract Input').first().json;
const message = $('Extract Input').first().json.message;
const allFiles = $json.files || [];
const staticData = $getWorkflowStaticData('global');

// Cache all file contents for Phase 2
// Reset execution-scoped static data from prior runs
staticData._buildAttempt = 0;
staticData._buildResult = {};
staticData._reviewResult = {};
staticData.p2Results = [];
staticData.allTasks = [];
staticData._pipelineReport = '';

// Extract project memory (if it exists) — pipeline-managed, not a code file
const memoryFile = allFiles.find(f => f.path === 'memory.md');
const projectMemory = memoryFile ? memoryFile.content : '';
staticData._projectMemory = projectMemory;

// Filter memory.md from file list so planner/coder can't modify it
const codeFiles = allFiles.filter(f => f.path !== 'memory.md');
staticData._allFileContents = codeFiles;

const fileList = codeFiles.map(f => f.path);

// Build API surface (exports from each file)
const apiSurface = [];
for (const f of allFiles) {
  if (!f.path.match(/\.(ts|tsx|js|jsx)$/) || f.path.includes('node_modules')) continue;
  const lines = (f.content || '').split('\n');
  const exports = [];
  for (const line of lines) {
    const trimmed = line.trim();
    if (/^export\s+default\s/.test(trimmed)) {
      exports.push(trimmed.replace(/\{[\s\S]*$/, '{...}').substring(0, 120));
    } else if (/^export\s+(const|let|var|function|class|interface|type|enum)\s/.test(trimmed)) {
      exports.push(trimmed.replace(/\{[\s\S]*$/, '{...}').replace(/=>[\s\S]*$/, '=> ...').substring(0, 150));
    } else if (/^export\s+\{/.test(trimmed)) {
      exports.push(trimmed.substring(0, 150));
    }
  }
  if (exports.length > 0) {
    apiSurface.push(`## ${f.path}\n${exports.join('\n')}`);
  }
}

// Extract dependencies from package.json
let dependencies = {};
let devDependencies = {};
let depNames = [];
for (const f of allFiles) {
  if (f.path === 'package.json' || f.path.endsWith('/package.json')) {
    try {
      const pkg = JSON.parse(f.content);
      dependencies = { ...dependencies, ...(pkg.dependencies || {}) };
      devDependencies = { ...devDependencies, ...(pkg.devDependencies || {}) };
      depNames = [...Object.keys(pkg.dependencies || {}), ...Object.keys(pkg.devDependencies || {})];
    } catch(e) {}
  }
}

// Build research docs string
const depList = Object.entries(dependencies).map(([k,v]) => `  ${k}: ${v}`).join('\n');
const devDepList = Object.entries(devDependencies).map(([k,v]) => `  ${k}: ${v}`).join('\n');
let researchDocs = '';
if (depList || devDepList) {
  researchDocs += '## Dependency Manifest\nOnly use packages listed here.\n';
  if (depList) researchDocs += `dependencies:\n${depList}\n`;
  if (devDepList) researchDocs += `devDependencies:\n${devDepList}\n`;
}
if (apiSurface.length > 0) {
  researchDocs += '\n## Project API Surface\nMatch these import/export signatures exactly when importing from project files.\n';
  researchDocs += apiSurface.join('\n\n');
}

// Cache for all downstream phases
staticData._researchDocs = researchDocs;
staticData._projectFileList = fileList;
staticData._projectApiSummary = apiSurface.join('\n');
staticData._projectDeps = depNames;

// Cache planner input in static data so Build Request can read it
// (Load Model HTTP response replaces $json, so downstream can't use $json)
staticData._plannerInput = {
  message,
  project_goal: memory.goal || message,
  project_id: memory.project_id,
  existing_files: fileList,
  api_summary: apiSurface.join('\n'),
  installed_packages: depNames,
  _scrapeData: memory._scrapeData || null,
  image_data: memory.image_data || null,
  project_memory: projectMemory
};

return [{ json: staticData._plannerInput }];

// Read planner input from static data (Load Model HTTP response replaces $json)
const staticData = $getWorkflowStaticData('global');
const plannerInput = staticData._plannerInput || {};
const message = plannerInput.message || '';
const existingFiles = plannerInput.existing_files || [];
const apiSummary = plannerInput.api_summary || '';
const installedPkgs = plannerInput.installed_packages || [];
const scrapeData = plannerInput._scrapeData;

let projectContext = '';
if (existingFiles.length > 0) {
  projectContext += `\n\nEXISTING PROJECT FILES (only reference files from this list):\n${existingFiles.join('\n')}\n`;
}
if (apiSummary) {
  projectContext += `\nAPI SURFACE (exports from each file):\n${apiSummary}\n`;
}
if (installedPkgs.length > 0) {
  projectContext += `\nINSTALLED PACKAGES (only reference packages from this list):\n${installedPkgs.join(', ')}\n`;
}

// Inject project memory for continuity across runs
const projectMemory = plannerInput.project_memory || '';
if (projectMemory) {
  projectContext += '\n\nPROJECT MEMORY (context from previous pipeline runs — use for continuity):\n' + projectMemory.substring(0, 4000) + '\n';
}

const plannerPrompt = `You are a Senior Software Architect and UI/UX Design Expert. Your job is to break a coding request into MULTIPLE structured tasks with detailed visual specifications.

DESIGN PRINCIPLES (apply to ALL task descriptions):
- Main interaction element must be centered and dominant (40-60% of viewport height)
- Use vertical single-column layouts for apps/games — never side-by-side grids unless explicitly requested
- Content hierarchy: hero/main action at top → stats/feedback → secondary actions (shop, settings) at bottom
- Mobile-first: everything fits in 100vh, no page-level scrollbars, internal scrolling only for lists
- Dark backgrounds with bright accent colors. Use gradients for depth (purple-900 to black, not flat colors)
- Every click/tap must produce visible feedback (scale animation, color flash, particle effect)
- Numbers should animate when they change (bounce, pulse, scale). Use tabular-nums for counters
- Cards: rounded-xl (12-16px), subtle shadows, semi-transparent backgrounds with backdrop-blur
- Buttons: press animation (scale 0.95), hover glow, disabled state with reduced opacity
- Color-code affordability: gold/amber = available, red/gray = locked, green = owned/success
- Typography: big bold numbers (text-4xl+), clear hierarchy via weight not just size
- Spacing: generous padding, never cramped. Mobile touch targets minimum 44px

WHEN A REFERENCE IMAGE IS PROVIDED:
- Describe the EXACT layout structure you see: column vs row, spacing ratios, component sizes
- Specify exact colors, gradients, border styles, and shadows visible in the image
- Note the visual hierarchy: what's biggest, what's brightest, what draws the eye first
- Describe animations or interactive states implied by the design (hover effects, active states)
- Include specific dimensions: "toilet button should be 150px diameter" not just "large button"
- The coder CANNOT see the image — your description is their ONLY reference Each task will be handled by a separate coder with 128K context who can write up to 6 files at once.\n\nOutput a JSON object with ONE field:\n\n"tasks": array of task objects. IMPORTANT: You MUST create multiple tasks. Group files by concern (e.g. styles in one task, frontend components in another, config in another). Each task has:\n- task_id: string like "TASK-001"\n- description: detailed actionable description of what to implement, including specific requirements, color values, component names, API endpoints, and behavior. The coder cannot see the original request — your description is all they get.\n- files: array of exact file paths to create or modify. List EVERY file this task needs — the coder can ONLY write files listed here. For existing projects, prefer modifying files from the EXISTING PROJECT FILES list. For new projects or missing functionality, CREATE new file paths as needed.\n- dependencies: array of task_id strings this task depends on (empty if none)\n- complexity: "low", "medium", or "high"
- needs_concept: boolean — set to true if this task involves UI/visual work that has NO reference image from the user. Set to false if the user provided a reference image that covers this task's visual design, or if the task is purely logic/config with no visual component.\n\nRULES:\n- Always split work across multiple tasks by concern: styles, components, routes, config, etc.\n- Each task can touch up to 12-15 files. The coder has 128K context and currently uses less than 2% of it — give it MORE work per task. Aim for 2-3 LARGE tasks instead of many small ones. A single task can contain an entire feature (components + hooks + styles + config). Fewer tasks = faster pipeline\n- The description must be SELF-CONTAINED — include ALL details the coder needs\n- For existing projects, reference files from the EXISTING PROJECT FILES list when modifying. You MAY create new files that do not exist yet.
- CRITICAL: For new projects (empty file list), you MUST include a setup task that creates: package.json (with ALL dependencies), index.html, vite.config.js (or next.config.js), tsconfig.json (if TypeScript), tailwind.config.js + postcss.config.js (if using Tailwind), and the main entry point (src/main.jsx or app/layout.tsx). The project MUST be buildable.\n- Detect the project type from the files and packages. If the project is a React/Vite frontend (no Express or backend framework in INSTALLED PACKAGES), focus all tasks on frontend files. Only create server/middleware/API handler tasks if Express or a similar backend framework is in INSTALLED PACKAGES.\n- In each task description, specify the EXACT import/export style each file should use (named vs default) based on the API SURFACE above.\n- NEVER create a task whose only purpose is deleting files. The coder cannot delete files — it can only create or modify. If dead files exist, ignore them. They do not affect the build.
- The FIRST task should always include project configuration files (package.json, config files, index.html) if they do not already exist. The project MUST compile and run after all tasks complete.
- NEVER include memory.md in any task's file list — it is managed by the pipeline
- Output ONLY the raw JSON object: {"tasks": [...]}\n- No markdown, no explanation — ONLY the JSON with tasks`;

let messageContent;
if (scrapeData && scrapeData.screenshot_b64) {
  const cssTokensStr = JSON.stringify(scrapeData.css_tokens, null, 2);
  const domStr = scrapeData.dom_summary || '';
  messageContent = [
    { type: 'image_url', image_url: { url: `data:image/png;base64,${scrapeData.screenshot_b64}` } },
    { type: 'text', text: `${plannerPrompt}\n\nREFERENCE DESIGN (screenshot above):\nCSS Tokens:\n${cssTokensStr}\n\nDOM Structure:\n${domStr}\n\nRequest: ${message}${projectContext}\n\n(Match the visual design, color palette, typography, and layout from the screenshot)` }
  ];
} else if (plannerInput.image_data) {
  const userImage = plannerInput.image_data;
  messageContent = [
    { type: 'image_url', image_url: { url: 'data:image/png;base64,' + userImage } },
    { type: 'text', text: plannerPrompt + '\n\nREFERENCE IMAGE (uploaded by user — replicate this design):\n\nRequest: ' + message + projectContext }
  ];
} else {
  messageContent = `${plannerPrompt}\n\nRequest: ${message}${projectContext}`;
}

return [{
  json: {
    model: $env.PLANNER_MODEL || 'qwen3.5-27b@q4_k_m',
    messages: [{ role: 'user', content: messageContent }],
    temperature: 1.0,
    top_p: 0.95,
    top_k: 20,
    min_p: 0.0,
    presence_penalty: 0.0,
    max_tokens: parseInt($env.PLANNER_MAX_TOKENS) || 32768,
    chat_template_kwargs: { enable_thinking: true, max_thinking_tokens: 4096 }
  }
}];

const raw = $json.choices[0].message.content || $json.choices[0].message.reasoning_content || '';
let content = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
if (content.includes('</think>')) content = content.split('</think>').pop().trim();
content = content.replace(/<\/?task>/g, '').trim();
content = content.replace(/\n+(?:Reasoning|Note|Explanation):[\s\S]*/i, '').trim();
content = content.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();

let tasks, planDocument = '';
try {
  const parsed = JSON.parse(content);
  if (Array.isArray(parsed)) {
    tasks = parsed;
  } else {
    tasks = parsed.tasks || [parsed];
    planDocument = parsed.plan_document || '';
  }
} catch (e) {
  // Truncated JSON recovery: extract complete task objects
  const tasksMatch = content.match(/"tasks"\s*:\s*\[/);
  if (tasksMatch) {
    const arrStart = content.indexOf('[', tasksMatch.index);
    let bracketDepth = 0;
    let lastCompleteObj = -1;
    for (let i = arrStart; i < content.length; i++) {
      if (content[i] === '{') bracketDepth++;
      if (content[i] === '}') {
        bracketDepth--;
        if (bracketDepth === 0) lastCompleteObj = i;
      }
    }
    if (lastCompleteObj > arrStart) {
      const recoveredArr = content.substring(arrStart, lastCompleteObj + 1) + ']';
      try {
        tasks = JSON.parse(recoveredArr);
      } catch (e2) {
        tasks = [{ task_id: 'TASK-FALLBACK-' + Date.now(), description: content, files: [], dependencies: [], complexity: 'high' }];
      }
    } else {
      tasks = [{ task_id: 'TASK-FALLBACK-' + Date.now(), description: content, files: [], dependencies: [], complexity: 'high' }];
    }
  } else {
    tasks = [{ task_id: 'TASK-FALLBACK-' + Date.now(), description: content, files: [], dependencies: [], complexity: 'high' }];
  }
}

tasks = tasks.map(t => ({
  ...t,
  files: t.files || [],
  dependencies: t.dependencies || [],
  complexity: t.complexity || 'medium'
}));

return [{ json: { tasks, plan_document: planDocument } }];

// Research: Fetch library docs — Context7 → Exa fallback → Magic UI
const http = require('http');
const https = require('https');
const staticData = $getWorkflowStaticData('global');
const allFiles = staticData._allFileContents || [];
const tasks = $json.tasks || [];

// ─── 1. Extract libraries from package.json + task text ─────────────
const libs = new Set();
const pkgFile = allFiles.find(f => f.path === 'package.json');
if (pkgFile) {
  try {
    const pkg = JSON.parse(pkgFile.content);
    for (const dep of Object.keys(pkg.dependencies || {})) libs.add(dep);
    for (const dep of Object.keys(pkg.devDependencies || {})) libs.add(dep);
  } catch(e) {}
}
const taskText = tasks.map(t => t.description || '').join(' ').toLowerCase();
const knownLibs = ['react', 'next', 'nextjs', 'vite', 'tailwindcss', 'tailwind', 'express', 'prisma', 'framer-motion', 'heroui', 'zustand', 'zod', 'three', 'react-three', 'r3f', 'drei', '@react-three/fiber', '@react-three/drei'];
for (const lib of knownLibs) {
  if (taskText.includes(lib)) {
    const mapped = {'nextjs':'next','tailwind':'tailwindcss','react-three':'@react-three/fiber','r3f':'@react-three/fiber','drei':'@react-three/drei'};
    libs.add(mapped[lib] || lib);
  }
}
if (allFiles.some(f => f.path.match(/\.(jsx|tsx)$/))) libs.add('react');
const skipList = new Set(['autoprefixer', 'postcss', 'typescript', 'vite', '@vitejs/plugin-react', '@types/react', '@types/node', '@types/react-dom', 'eslint', 'prettier', 'react', 'react-dom', 'tailwindcss', 'tailwind', '@fontsource/inter', '@fontsource/fira-code']);
const toFetch = [...libs].filter(l => !skipList.has(l)).slice(0, 7);

if (toFetch.length === 0) {
  staticData._researchDocs = '';
  return [{ json: $json }];
}

// ─── 2. MCP helpers ─────────────────────────────────────────────────
function mcpRequest(sessionId, method, params) {
  return new Promise((resolve, reject) => {
    const body = JSON.stringify({ jsonrpc: '2.0', method, params, id: Date.now() });
    const req = http.request({
      hostname: 'docky', port: 8811, path: '/mcp', method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Accept': 'application/json, text/event-stream',
        'Content-Length': Buffer.byteLength(body),
        ...(sessionId ? { 'Mcp-Session-Id': sessionId } : {})
      }
    }, res => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => resolve({ data, sessionId: res.headers['mcp-session-id'] }));
    });
    req.on('error', reject);
    req.setTimeout(20000, () => { req.destroy(); reject(new Error('timeout')); });
    req.write(body); req.end();
  });
}

// Exa MCP helper (HTTPS to mcp.exa.ai)
function exaRequest(sessionId, method, params) {
  return new Promise((resolve, reject) => {
    const body = JSON.stringify({ jsonrpc: '2.0', method, params, id: Date.now() });
    const headers = {
      'Content-Type': 'application/json',
      'Accept': 'application/json, text/event-stream',
      'Content-Length': Buffer.byteLength(body),
    };
    if (sessionId) headers['Mcp-Session-Id'] = sessionId;
    const req = https.request({
      hostname: 'mcp.exa.ai', port: 443, path: '/mcp', method: 'POST', headers
    }, res => {
      let data = '';
      if (!sessionId && res.headers['mcp-session-id']) {
        sessionId = res.headers['mcp-session-id'];
      }
      res.on('data', c => data += c);
      res.on('end', () => resolve({ data, sessionId }));
    });
    req.on('error', reject);
    req.setTimeout(30000, () => { req.destroy(); reject(new Error('exa timeout')); });
    req.write(body); req.end();
  });
}

function parseSSE(raw) {
  for (const line of raw.split('\n')) {
    if (line.startsWith('data: ') || line.startsWith('data:')) {
      const payload = line.startsWith('data: ') ? line.slice(6) : line.slice(5);
      try { return JSON.parse(payload); } catch(e) {}
    }
  }
  try { return JSON.parse(raw); } catch(e) {}
  return {};
}

const docs = [];
const errors = [];
let docSource = 'none';

// ─── 3. Try Context7 first ──────────────────────────────────────────
try {
  const init = await mcpRequest(null, 'initialize', {
    protocolVersion: '2024-11-05', capabilities: {},
    clientInfo: { name: 'eek-go-research', version: '1.0' }
  });
  const sid = init.sessionId;
  if (!sid) throw new Error('No MCP session ID');

  for (const lib of toFetch) {
    try {
      const resolve = await mcpRequest(sid, 'tools/call', {
        name: 'resolve-library-id', arguments: { libraryName: lib }
      });
      const resolveData = parseSSE(resolve.data);
      const resolveText = (resolveData.result?.content || []).map(c => c.text || '').join('');
      if (resolveText.includes('Failed to retrieve')) { errors.push(lib + ': ctx7 failed'); continue; }
      const idMatch = resolveText.match(/Context7-compatible library ID:\s*(\/[\w.-]+\/[\w.-]+)/);
      if (!idMatch) { errors.push(lib + ': no ID'); continue; }

      const docsResp = await mcpRequest(sid, 'tools/call', {
        name: 'get-library-docs',
        arguments: { context7CompatibleLibraryID: idMatch[1], tokens: 5000, topic: 'setup components hooks API examples' }
      });
      const docsData = parseSSE(docsResp.data);
      const docText = (docsData.result?.content || []).map(c => c.text || '').join('');
      if (docText.length > 100 && !docText.includes('Failed to retrieve')) {
        docs.push('## ' + lib + '\n' + docText.substring(0, 8000));
        docSource = 'context7';
      }
    } catch(e) { errors.push(lib + ': ' + e.message); }
  }
} catch(e) {
  errors.push('ctx7 init: ' + e.message);
}


// ─── 3.5. GSAP MCP docs — if project uses GSAP ────────────────────
if (libs.has('gsap') || taskText.includes('gsap') || taskText.includes('scroll') || taskText.includes('animation')) {
  try {
    const gsapInit = await mcpRequest(null, 'initialize', {
      protocolVersion: '2024-11-05', capabilities: {},
      clientInfo: { name: 'eek-go-gsap', version: '1.0' }
    });
    const gsapSid = gsapInit.sessionId;
    if (gsapSid) {
      // Get GSAP API docs for key APIs
      const gsapApis = ['ScrollTrigger', 'gsap.to', 'gsap.from', 'gsap.timeline'];
      const gsapDocs = [];
      for (const api of gsapApis) {
        try {
          const gsapResp = await mcpRequest(gsapSid, 'tools/call', {
            name: 'get_gsap_api_expert',
            arguments: { api_element: api, level: 'intermediate' }
          });
          const gsapData = parseSSE(gsapResp.data);
          const gsapText = (gsapData.result?.content || []).map(c => c.text || '').join('');
          if (gsapText.length > 100 && !gsapText.includes('Error')) {
            gsapDocs.push('### ' + api + '\n' + gsapText.substring(0, 3000));
          }
        } catch(e) { errors.push('gsap-api-' + api + ': ' + e.message); }
      }
      if (gsapDocs.length > 0) {
        docs.push('## GSAP API Reference (from GSAP Master MCP)\n' + gsapDocs.join('\n\n'));
        docSource = docSource || 'gsap-mcp';
      }
    }
  } catch(e) {
    errors.push('gsap-mcp: ' + e.message);
  }
}

// ─── 4. Exa fallback — if Context7 returned 0 docs ─────────────────
if (docs.length === 0) {
  try {
    const exaInit = await exaRequest(null, 'initialize', {
      protocolVersion: '2024-11-05', capabilities: {},
      clientInfo: { name: 'eek-go-research', version: '1.0' }
    });
    const exaSid = exaInit.sessionId;

    // Build TARGETED queries from task descriptions, not generic library names
    const mainLibs = toFetch.filter(l => !l.startsWith('@types'));
    const queries = [];

    // Extract specific features/APIs mentioned in tasks
    const allTaskText = tasks.map(t => (t.description || '')).join(' ');

    for (const lib of mainLibs.slice(0, 4)) {
      // Find what the task actually needs from this library
      const libLower = lib.toLowerCase();
      const taskWords = allTaskText.split(/[\s.,;:]+/).filter(w => w.length > 3);

      // Look for API names, component names, or feature keywords near the library mention
      const relevantTerms = [];
      const taskLower = allTaskText.toLowerCase();
      const libIdx = taskLower.indexOf(libLower);
      if (libIdx >= 0) {
        // Get ~200 chars around the library mention for context
        const nearby = allTaskText.substring(Math.max(0, libIdx - 100), Math.min(allTaskText.length, libIdx + 200));
        // Extract capitalized words (likely API names) and quoted strings
        const apiNames = nearby.match(/[A-Z][a-zA-Z]+(?:Router|Provider|Context|Hook|Plugin|Trigger|Effect|Animation)?/g) || [];
        relevantTerms.push(...apiNames.slice(0, 3));
      }

      // Build a specific query
      const specifics = relevantTerms.length > 0 ? ' ' + relevantTerms.join(' ') : '';
      queries.push(lib + specifics + ' usage examples API reference');
    }

    // If no libs to fetch but tasks mention specific tech, search for that
    if (queries.length === 0 && allTaskText.length > 50) {
      const techMentions = allTaskText.match(/(?:GSAP|ScrollTrigger|framer.motion|react.router|BrowserRouter|createBrowserRouter|useEffect|useState)/gi) || [];
      if (techMentions.length > 0) {
        queries.push(techMentions.slice(0, 3).join(' ') + ' usage examples documentation');
      }
    }

    for (const query of queries.slice(0, 3)) {
      try {
        const resp = await exaRequest(exaSid, 'tools/call', {
          name: 'get_code_context_exa',
          arguments: { query, num_results: 2 }
        });
        const respData = parseSSE(resp.data);
        const text = (respData.result?.content || []).map(c => c.text || '').join('');
        if (text.length > 200) {
          // Trim to 6K chars per query to keep total context reasonable
          docs.push('## Docs: ' + query.split(' API ')[0] + '\n' + text.substring(0, 6000));
          docSource = 'exa';
        }
      } catch(e) { errors.push('exa: ' + e.message); }
    }
  } catch(e) {
    errors.push('exa init: ' + e.message);
  }
}

// ─── 5. Design guide (always included) ──────────────────────────────
const designGuide = `## UI/UX Design Principles for Web Applications

### Layout
- Main interaction element must be centered and visually dominant (40-60% of viewport)
- Use vertical single-column layouts for game/app UIs — never side-by-side grids unless it's a dashboard
- Content hierarchy: hero/main action → stats/feedback → secondary actions (shop, settings)
- Mobile-first: everything should work on a 375px wide screen and scale up
- Scrollable secondary content (shops, lists) should never push the main interaction off-screen

### Visual Feedback
- Every user interaction (click, purchase, hover) MUST produce visible feedback
- Number changes should animate (bounce, scale pulse, color flash)
- Buttons: press animation (scale 0.95), hover glow/lift, disabled state with reduced opacity
- Success actions: green flash, checkmark, particle burst
- Use CSS transitions (200-300ms) on all interactive elements

### Color & Contrast
- Dark backgrounds with bright accent colors for maximum contrast
- Use gradients over flat colors for depth (e.g., purple-900 to indigo-950)
- Interactive elements should be the brightest items on screen
- Text must have sufficient contrast — white/yellow on dark, with text-shadow for readability

### Typography
- Big, bold numbers for scores/stats (text-4xl to text-6xl)
- Clear hierarchy: title (bold, large) → subtitle (medium) → body (regular, smaller)
