  // Split existing into base goal and refinements
  const refinementMarker = '\n\n**Refinements:**';
  const [baseGoal, existingRefinements] = existingGoalRaw.split(refinementMarker);
  const priorRefinements = existingRefinements ? existingRefinements.trim().split('\n').filter(l => l.startsWith('- ')) : [];

  // Only add refinement for feature/styling requests, not pure bug fixes
  const isFeatureOrStyle = msgLower.match(/add|new|feature|implement|create|change|make|style|design|layout|color|theme|bigger|smaller|move|redesign|update|improve/);

  if (isFeatureOrStyle && iterNum > 1) {
    const refinement = '- ' + requestSummary.substring(0, 80) + ' (Iteration ' + iterNum + ')';
