    if (!priorRefinements.some(r => r.substring(0, 40) === refinement.substring(0, 40))) {
      priorRefinements.push(refinement);
    }
  }

  // Keep last 8 refinements
  const recentRefinements = priorRefinements.slice(-8);
  projectGoal = baseGoal + (recentRefinements.length > 0 ? refinementMarker + '\n' + recentRefinements.join('\n') : '');
}

