  const errCount = (consoleResult.errors || []).length;
  const warnCount = (consoleResult.warnings || []).length;
  const cbBody = JSON.stringify({
    event: consoleResult.page_error ? 'console_check_failed' : (errCount > 0 ? 'console_check_failed' : 'console_check_passed'),
    project_id: projectId,
    data: { errors: errCount, warnings: warnCount, page_error: consoleResult.page_error || null, audits: { visibility: (audits.visibility || {}).total, links: (audits.links || {}).broken?.length || 0, images: (audits.images || {}).broken?.length || 0, contrast: (audits.contrast || {}).failures?.length || 0, content_coverage: (audits.content || {}).coveragePercent } }
  });
  const cbReq = http.request({
    hostname: 'forge', port: 3500, path: '/api/status-callback', method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(cbBody) }
  });
  cbReq.on('error', () => {});
  cbReq.write(cbBody); cbReq.end();
} catch {}

return [{ json: $json }];

const http = require('http');
const LM_KEY = $env.LLM_API_KEY || '';
const HOST = '10.0.0.100';

// Unload all models
const models = await new Promise((resolve) => {
  const req = http.request({
    hostname: HOST, port: 1234, method: 'GET', path: '/api/v1/models',
    headers: { 'Authorization': 'Bearer ' + LM_KEY }, timeout: 10000
  }, res => {
    let data = ''; res.on('data', c => data += c);
    res.on('end', () => { try { resolve(JSON.parse(data)); } catch { resolve({ models: [] }); } });
  });
  req.on('error', () => resolve({ models: [] }));
  req.end();
});

for (const m of (models.models || [])) {
  for (const inst of (m.loaded_instances || [])) {
    try {
      const body = JSON.stringify({ instance_id: inst.id || m.key });
      await new Promise((resolve) => {
        const req = http.request({
          hostname: HOST, port: 1234, method: 'POST', path: '/api/v1/models/unload',
          headers: { 'Authorization': 'Bearer ' + LM_KEY, 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(body) },
          timeout: 15000
        }, res => { let d = ''; res.on('data', c => d += c); res.on('end', () => resolve(d)); });
        req.on('error', () => resolve(''));
        req.write(body); req.end();
      });
    } catch {}
  }
}

