const http = require('http');
const projectId = $('Extract Input').first().json.project_id || 'unknown';
const userMessage = ($('Extract Input').first().json.message || '').substring(0, 80);
const staticData = $getWorkflowStaticData('global');
const buildPassed = (staticData._buildResult || {}).success;
const quality = ((staticData._reviewResult || {}).code_quality) || '?';

const commitMsg = 'Pipeline: ' + (buildPassed ? 'PASS' : 'FAIL') + ' q=' + quality + ' — ' + userMessage;

const body = JSON.stringify({ message: commitMsg });
const result = await new Promise((resolve) => {
  const req = http.request({
    hostname: 'file-api', port: 3456, method: 'POST',
    path: '/projects/' + projectId + '/git-commit',
    headers: {
      'Authorization': 'Bearer ' + ($env.FILE_API_TOKEN || ''),
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(body)
    },
    timeout: 15000
  }, res => {
    let data = '';
    res.on('data', c => data += c);
    res.on('end', () => { try { resolve(JSON.parse(data)); } catch { resolve({ success: false }); } });
  });
  req.on('error', () => resolve({ success: false }));
  req.write(body); req.end();
});

return [{ json: { ...$json, git_commit: result } }];
